    44	func pseudoSelectivity(sctx planctx.PlanContext, coll *statistics.HistColl, exprs []expression.Expression) float64 {
    45		minFactor := selectionFactor
    46		colExists := make(map[string]bool)
    47		for _, expr := range exprs {
    48			fun, ok := expr.(*expression.ScalarFunction)
    49			if !ok {
    50				continue
    51			}
    52			colID := getConstantColumnID(fun.GetArgs())
    53			if colID == unknownColumnID {
    54				continue
    55			}
    56			statistics.ColumnStatsIsInvalid((*statistics.Column)(nil), sctx, coll, colID)
    57			switch fun.FuncName.L {
    58			case ast.EQ, ast.NullEQ, ast.In:
    59				minFactor = math.Min(minFactor, 1.0/pseudoEqualRate)
    60				col := coll.GetCol(colID)
    61				if col == nil {
    62					continue
    63				}
    64				colExists[col.Info.Name.L] = true
    65				if mysql.HasUniKeyFlag(col.Info.GetFlag()) {
    66					return 1.0 / float64(coll.RealtimeCount)
    67				}
    68			case ast.GE, ast.GT, ast.LE, ast.LT:
    69				minFactor = math.Min(minFactor, 1.0/pseudoLessRate)
    70				// FIXME: To resolve the between case.
    71			}
    72		}
    73		if len(colExists) == 0 {
    74			return minFactor
    75		}
    76		// use the unique key info
    77		hasUniqueKey := false
    78		coll.ForEachIndexImmutable(func(_ int64, idx *statistics.Index) bool {
    79			unique := true
    80			firstMatch := false
    81			for _, col := range idx.Info.Columns {
    82				if !colExists[col.Name.L] {
    83					unique = false
    84					break
    85				}
    86				firstMatch = true
    87			}
    88			if firstMatch {
    89				// This might trigger the statistics load.
    90				statistics.IndexStatsIsInvalid(sctx, (*statistics.Index)(nil), coll, idx.ID)
    91			}
    92			if idx.Info.Unique && unique {
    93				hasUniqueKey = true
    94				return true
    95			}
    96			return false
    97		})
    98		if hasUniqueKey {
    99			return 1.0 / float64(coll.RealtimeCount)
   100		}
   101		return minFactor
   102	}
