   176	func getPseudoRowCountByIndexRanges(tc types.Context, indexRanges []*ranger.Range,
   177		tableRowCount float64, colsLen int) (float64, error) {
   178		if tableRowCount == 0 {
   179			return 0, nil
   180		}
   181		var totalCount float64
   182		for _, indexRange := range indexRanges {
   183			count := tableRowCount
   184			i, err := indexRange.PrefixEqualLen(tc)
   185			if err != nil {
   186				return 0, errors.Trace(err)
   187			}
   188			if i == colsLen && !indexRange.LowExclude && !indexRange.HighExclude {
   189				totalCount += 1.0
   190				continue
   191			}
   192			if i >= len(indexRange.LowVal) {
   193				i = len(indexRange.LowVal) - 1
   194			}
   195			rowCount, err := getPseudoRowCountByColumnRanges(tc, tableRowCount, []*ranger.Range{indexRange}, i)
   196			if err != nil {
   197				return 0, errors.Trace(err)
   198			}
   199			count = count / tableRowCount * rowCount
   200			// If the condition is a = 1, b = 1, c = 1, d = 1, we think every a=1, b=1, c=1 only filtrate 1/100 data,
   201			// so as to avoid collapsing too fast.
   202			for j := 0; j < i; j++ {
   203				count = count / float64(100)
   204			}
   205			totalCount += count
   206		}
   207		if totalCount > tableRowCount {
   208			totalCount = tableRowCount / 3.0
   209		}
   210		return totalCount, nil
   211	}
