   213	// getPseudoRowCountByColumnRanges calculate the row count by the ranges if there's no statistics information for this column.
   214	func getPseudoRowCountByColumnRanges(tc types.Context, tableRowCount float64, columnRanges []*ranger.Range, colIdx int) (float64, error) {
   215		var rowCount float64
   216		for _, ran := range columnRanges {
   217			if ran.LowVal[colIdx].Kind() == types.KindNull && ran.HighVal[colIdx].Kind() == types.KindMaxValue {
   218				rowCount += tableRowCount
   219			} else if ran.LowVal[colIdx].Kind() == types.KindMinNotNull {
   220				nullCount := tableRowCount / pseudoEqualRate
   221				if ran.HighVal[colIdx].Kind() == types.KindMaxValue {
   222					rowCount += tableRowCount - nullCount
   223				} else {
   224					lessCount := tableRowCount / pseudoLessRate
   225					rowCount += lessCount - nullCount
   226				}
   227			} else if ran.HighVal[colIdx].Kind() == types.KindMaxValue {
   228				rowCount += tableRowCount / pseudoLessRate
   229			} else {
   230				compare, err := ran.LowVal[colIdx].Compare(tc, &ran.HighVal[colIdx], ran.Collators[colIdx])
   231				if err != nil {
   232					return 0, errors.Trace(err)
   233				}
   234				if compare == 0 {
